const body = $input.item.json.body || $input.item.json;
const type = body.notification_type || 'unknown';
const summary = body.summary || '';
const deepLink = body.deep_link_url || '';
const urgency = body.urgency || 'low';
const signalIds = (body.signal_ids || []).join(', ');

const EMOJI = {
  daily_briefing: '\u{1F4CA}',
  escalation_alert: '\u{1F6A8}',
  veto_reminder: '\u{23F0}',
  weekly_digest: '\u{1F4CB}',
};
const emoji = EMOJI[type] || '\u{1F514}';

const TITLE = {
  daily_briefing: 'Daily Briefing',
  escalation_alert: 'Escalation Alert',
  veto_reminder: 'Veto Reminder',
  weekly_digest: 'Weekly Digest',
};
const title = TITLE[type] || type;

let lines = [
  `${emoji} *Intelligence: ${title}*`,
  '',
  summary,
];

if (deepLink) {
  lines.push('');
  lines.push(`[Open Dashboard](${deepLink})`);
}

if (signalIds) {
  lines.push('');
  lines.push(`_Signals: ${signalIds}_`);
}

return { json: { message: lines.join('\n'), urgency } };
